solution_code:
#include <iostream>

int diff_and_product(int a, int b) {
    std::cerr << "[bp] diff_and_product a=" << a << " b=" << b << "\n";
    int diff = a - b;
    std::cerr << "[bp] diff=" << diff << "\n";
    int product = a * b;
    std::cerr << "[bp] product=" << product << "\n";
    return diff + product;
}

int main() {
    int a, b;
    std::cin >> a >> b;
    std::cout << diff_and_product(a, b) << "\n";
    return 0;
}
